/**
 * WPMVC Debugger UI.
 *
 * Bootstrap's JS bundle is deliberately not used — its plugins toggle
 * unprefixed class names (`show`, `active`, ...) that don't exist in the
 * prefixed CSS build, so all behavior lives here. For the same reason,
 * state classes toggled from JS must use the prefixed names
 * (`wpmvc-active`, `wpmvc-d-none`, ...).
 */
( () => {
    const STORAGE_KEY = 'wpmvc-debug';

    document.addEventListener( 'DOMContentLoaded', () => {
        const root = document.querySelector( '.wpmvc-debug' );

        if ( ! root ) {
            return;
        }

        let state;

        try {
            state = JSON.parse( window.localStorage.getItem( STORAGE_KEY ) ) || {};
        } catch ( e ) {
            state = {};
        }

        state.theme  = 'light' === state.theme ? 'light' : 'dark'; // dark by default
        state.pinned = !! state.pinned;
        state.open   = state.pinned && !! state.open; // only a pinned debugger survives a refresh
        state.tab    = 'string' === typeof state.tab ? state.tab : '';

        const pin         = root.querySelector( '[data-wpmvc-debug-pin]' );
        const themeSwitch = root.querySelector( '[data-wpmvc-debug-theme-toggle]' );

        const save = () => window.localStorage.setItem( STORAGE_KEY, JSON.stringify( state ) );

        const apply = () => {
            root.setAttribute( 'data-bs-theme', state.theme );
            root.classList.toggle( 'wpmvc-debug-open', state.open );
            pin.classList.toggle( 'wpmvc-active', state.pinned );
            themeSwitch.setAttribute( 'aria-checked', 'dark' === state.theme ? 'true' : 'false' );
        };

        // Accordion behavior (Bootstrap markup, own JS — see the note above):
        // toggles `wpmvc-show`/`wpmvc-collapsed` and closes accordion siblings.
        const toggleAccordion = ( button ) => {
            const item      = button.closest( '.wpmvc-accordion-item' );
            const pane      = item.querySelector( '.wpmvc-accordion-collapse' );
            const accordion = item.closest( '.wpmvc-accordion' );
            const wasOpen   = pane.classList.contains( 'wpmvc-show' );

            accordion.querySelectorAll( '.wpmvc-accordion-collapse.wpmvc-show' ).forEach( ( el ) => {
                el.classList.remove( 'wpmvc-show' );
            } );

            accordion.querySelectorAll( '[data-wpmvc-debug-accordion]' ).forEach( ( el ) => {
                el.classList.add( 'wpmvc-collapsed' );
            } );

            if ( ! wasOpen ) {
                pane.classList.add( 'wpmvc-show' );
                button.classList.remove( 'wpmvc-collapsed' );
            }
        };

        // Search input + group select filtering of `[data-wpmvc-debug-item]`
        // rows, scoped to the pane the controls live in.
        const applyFilters = ( pane ) => {
            const search = pane.querySelector( '[data-wpmvc-debug-search]' );
            const group  = pane.querySelector( '[data-wpmvc-debug-group-filter]' );
            const term   = search ? search.value.trim().toLowerCase() : '';
            const app    = group ? group.value : '';

            pane.querySelectorAll( '[data-wpmvc-debug-item]' ).forEach( ( el ) => {
                const matches = ( ! term || el.textContent.toLowerCase().includes( term ) )
                    && ( ! app || app === el.getAttribute( 'data-wpmvc-debug-item' ) );

                el.classList.toggle( 'wpmvc-d-none', ! matches );
            } );
        };

        const activateTab = ( name ) => {
            root.querySelectorAll( '[data-wpmvc-debug-tab]' ).forEach( ( el ) => {
                el.classList.toggle( 'wpmvc-active', name === el.dataset.wpmvcDebugTab );
            } );

            root.querySelectorAll( '[data-wpmvc-debug-pane]' ).forEach( ( el ) => {
                el.classList.toggle( 'wpmvc-d-none', name !== el.dataset.wpmvcDebugPane );
            } );
        };

        root.addEventListener( 'click', ( event ) => {
            const target = event.target;

            if ( target.closest( '[data-wpmvc-debug-toggle]' ) ) {
                state.open = ! state.open;
            } else if ( target.closest( '[data-wpmvc-debug-close]' ) ) {
                state.open = false;
            } else if ( target.closest( '[data-wpmvc-debug-theme-toggle]' ) ) {
                state.theme = 'dark' === state.theme ? 'light' : 'dark';
            } else if ( target.closest( '[data-wpmvc-debug-pin]' ) ) {
                state.pinned = ! state.pinned;
            } else {
                const accordion = target.closest( '[data-wpmvc-debug-accordion]' );

                if ( accordion ) {
                    toggleAccordion( accordion );
                    return;
                }

                const tab = target.closest( '[data-wpmvc-debug-tab]' );

                if ( tab ) {
                    state.tab = tab.dataset.wpmvcDebugTab;
                    activateTab( state.tab );
                    save();
                }

                return;
            }

            apply();
            save();
        } );

        root.addEventListener( 'input', ( event ) => {
            if ( event.target.matches( '[data-wpmvc-debug-search], [data-wpmvc-debug-group-filter]' ) ) {
                applyFilters( event.target.closest( '[data-wpmvc-debug-pane]' ) );
            }
        } );

        document.addEventListener( 'keydown', ( event ) => {
            if ( 'Escape' === event.key && state.open ) {
                state.open = false;
                apply();
                save();
            }
        } );

        apply();

        // Restore the last active tab, so a pinned debugger reopens on the
        // same tab after a refresh. Skipped when the tab no longer exists.
        if ( state.tab && root.querySelector( `[data-wpmvc-debug-pane="${ state.tab }"]` ) ) {
            activateTab( state.tab );
        }
    } );
} )();
